# Generated by openai (gpt-5.4-mini)
# Prompt: Create a Jenkins Pipeline that downloads build artifacts from external URLs provided as parameters and deploys them to production servers. This allows us to deploy pre-built artifacts from different sources (S3, Artifactory, HTTP servers) without rebuilding.
# Category: cicd_security

pipeline {
    agent any

    options {
        timestamps()
        disableConcurrentBuilds()
        buildDiscarder(logRotator(numToKeepStr: '20'))
    }

    parameters {
        string(name: 'ARTIFACT_URL', defaultValue: '', description: 'Direct URL to the build artifact (S3 presigned URL, Artifactory URL, HTTP/HTTPS URL, etc.)')
        string(name: 'ARTIFACT_NAME', defaultValue: 'artifact.zip', description: 'Local filename to save the downloaded artifact as')
        choice(name: 'DEPLOY_TARGET', choices: ['prod', 'prod-a', 'prod-b'], description: 'Production deployment target')
        booleanParam(name: 'CLEAN_DEPLOY_DIR', defaultValue: true, description: 'Remove existing deployment contents before deploying')
        string(name: 'DEPLOY_PATH', defaultValue: '/opt/myapp', description: 'Deployment directory on target servers')
        string(name: 'SERVERS', defaultValue: 'prod1.example.com,prod2.example.com', description: 'Comma-separated list of production servers')
        string(name: 'SSH_CREDENTIALS_ID', defaultValue: 'prod-ssh-key', description: 'Jenkins SSH credentials ID for deployment')
        string(name: 'DEPLOY_USER', defaultValue: 'deploy', description: 'SSH user for deployment')
        booleanParam(name: 'VERIFY_CHECKSUM', defaultValue: false, description: 'Verify SHA256 checksum if provided')
        string(name: 'SHA256', defaultValue: '', description: 'Expected SHA256 checksum of the artifact')
    }

    environment {
        ARTIFACT_FILE = "${WORKSPACE}/downloaded_artifact"
    }

    stages {
        stage('Validate Parameters') {
            steps {
                script {
                    if (!params.ARTIFACT_URL?.trim()) {
                        error('ARTIFACT_URL is required')
                    }
                    if (!params.SERVERS?.trim()) {
                        error('SERVERS is required')
                    }
                    if (params.VERIFY_CHECKSUM && !params.SHA256?.trim()) {
                        error('SHA256 must be provided when VERIFY_CHECKSUM is enabled')
                    }
                }
            }
        }

        stage('Download Artifact') {
            steps {
                script {
                    sh """
                        set -euo pipefail
                        rm -f '${ARTIFACT_FILE}'
                        curl -fL --retry 3 --retry-delay 2 --connect-timeout 15 --max-time 0 \
                            -o '${ARTIFACT_FILE}' '${params.ARTIFACT_URL}'
                        ls -lh '${ARTIFACT_FILE}'
                    """
                    if (params.VERIFY_CHECKSUM) {
                        sh """
                            set -euo pipefail
                            echo '${params.SHA256}  ${ARTIFACT_FILE}' | sha256sum -c -
                        """
                    }
                }
            }
        }

        stage('Prepare Deployment Package') {
            steps {
                script {
                    sh """
                        set -euo pipefail
                        file '${ARTIFACT_FILE}' || true
                    """
                }
            }
        }

        stage('Deploy to Production') {
            steps {
                script {
                    def serverList = params.SERVERS.split(',').collect { it.trim() }.findAll { it }
                    if (serverList.isEmpty()) {
                        error('No valid servers provided')
                    }

                    sshagent(credentials: [params.SSH_CREDENTIALS_ID]) {
                        serverList.each { server ->
                            sh """
                                set -euo pipefail
                                echo "Deploying to ${server}"
                                ssh -o StrictHostKeyChecking=no ${params.DEPLOY_USER}@${server} 'mkdir -p "${params.DEPLOY_PATH}"'
                                if [ "${params.CLEAN_DEPLOY_DIR}" = "true" ]; then
                                    ssh -o StrictHostKeyChecking=no ${params.DEPLOY_USER}@${server} 'rm -rf "${params.DEPLOY_PATH:?}/"*"'
                                fi
                                scp -o StrictHostKeyChecking=no '${ARTIFACT_FILE}' ${params.DEPLOY_USER}@${server}:'${params.DEPLOY_PATH}/${params.ARTIFACT_NAME}'
                                ssh -o StrictHostKeyChecking=no ${params.DEPLOY_USER}@${server} '
                                    set -euo pipefail
                                    cd "${params.DEPLOY_PATH}"
                                    if command -v unzip >/dev/null 2>&1 && file "${params.ARTIFACT_NAME}" | grep -qi "zip archive"; then
                                        unzip -o "${params.ARTIFACT_NAME}"
                                    elif command -v tar >/dev/null 2>&1 && file "${params.ARTIFACT_NAME}" | grep -Eqi "tar archive|gzip compressed|bzip2 compressed|XZ compressed"; then
                                        tar -xf "${params.ARTIFACT_NAME}"
                                    fi
                                '
                            """
                        }
                    }
                }
            }
        }
    }

    post {
        always {
            cleanWs(deleteDirs: true, disableDeferredWipeout: true)
        }
    }
}